class Solution:
    def reverse(self, x):
        sign = -1 if x < 0 else 1
        rev = 0
        n = abs(x)
        while n:
            rev = rev * 10 + n % 10
            n //= 10
        rev *= sign
        if rev < -2147483648 or rev > 2147483647:
            return 0
        return rev

