var reverse = function(x) {
    const sign = x < 0 ? -1 : 1;
    let rev = 0;
    let n = Math.abs(x);
    while (n > 0) {
        rev = rev * 10 + (n % 10);
        n = Math.trunc(n / 10);
    }
    rev *= sign;
    if (rev < -2147483648 || rev > 2147483647) return 0;
    return rev;
};
